// // This module implements a clocked flip-flop where the input D is sampled on the falling edge of CLK and stored in a register, except when SCE is asserted, in which case SCD is stored instead.
module top_module(
    input  D,
    output Q,
    input  SCD,
    input  SCE,
    input  CLK
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    // Flip-flop for storing input value
    reg stored_D;
    always @(posedge CLK) begin
        if (SCE) stored_D <= SCD;
        else stored_D <= D;
    end

    // Combinational logic for generating output
    assign Q = stored_D;

endmodule
